sp_widget.client_script:
api.controller = function ($scope) {
    // ── DOM references ────────────────────────────────────────────────────────
    var tableInput       = document.getElementById('tableInput');
    var queryInput       = document.getElementById('queryInput');
    var datefieldInput   = document.getElementById('datefieldInput');
    var confidenceInput  = document.getElementById('confidenceInput');
    var iterationsInput  = document.getElementById('iterationsInput');
    var daysInput        = document.getElementById('daysInput');
    var tasksInput       = document.getElementById('tasksInput');
    var runButton        = document.getElementById('runButton');
    var daysLabel        = document.getElementById('daysLabel');
    var tasksLabel       = document.getElementById('tasksLabel');
    var throughputDisplay = document.getElementById('throughputConfidenceDisplay');
    var completionDisplay = document.getElementById('completionConfidenceDisplay');

    if (!runButton) { console.error("Widget elements not found."); return; }

    // ── State ─────────────────────────────────────────────────────────────────
    var confidenceValue      = 85;
    var throughputData       = $scope.data.throughputHistogramData || [];
    var completionData       = $scope.data.completionHistogramData || [];
    var throughputBinWidth   = $scope.data.throughputBinWidth || 1;
    var completionBinWidth   = $scope.data.completionBinWidth || 1;
    var throughputChart      = null;
    var completionChart      = null;

    // ── Chart renderers ───────────────────────────────────────────────────────
    function renderThroughputChart(histData, confidence) {
        histData.sort(function (a, b) { return a.throughput - b.throughput; });

        // Right-to-left: at least X tasks with confidence%
        var total = histData.reduce(function (s, d) { return s + d.frequency; }, 0);
        var cumulative = 0;
        var percentile = null;
        for (var i = histData.length - 1; i >= 0; i--) {
            cumulative += histData[i].frequency;
            if (cumulative / total >= confidence / 100) {
                percentile = histData[i].throughput;
                break;
            }
        }

        throughputDisplay.textContent = confidence + '% (' + percentile + ' tasks)';

        if (throughputChart) { throughputChart.destroy(); }
        throughputChart = new Chart(
            document.getElementById('throughputChart').getContext('2d'), {
            type: 'bar',
            data: {
                labels: histData.map(function (d) { return d.throughput; }),
                datasets: [{
                    label: 'Occurrences',
                    data: histData.map(function (d) { return d.frequency; }),
                    backgroundColor: 'rgba(75, 192, 192, 0.2)',
                    borderColor: 'rgba(75, 192, 192, 1)',
                    borderWidth: 1,
                    barPercentage: 1.0,
                    categoryPercentage: 1.0
                }]
            },
            options: {
                plugins: {
                    annotation: {
                        annotations: {
                            confidenceLine: {
                                type: 'line',
                                xMin: percentile,
                                xMax: percentile,
                                borderColor: 'red',
                                borderWidth: 2,
                                label: {
                                    content: String(percentile),
                                    enabled: true,
                                    position: 'start',
                                    backgroundColor: 'rgba(255, 99, 132, 0.8)',
                                    color: 'white',
                                    font: { size: 12, weight: 'bold' },
                                    padding: 6
                                }
                            }
                        }
                    }
                },
                scales: {
                    x: { type: 'linear', title: { display: true, text: 'Number of Tasks' } },
                    y: { beginAtZero: true, title: { display: true, text: 'Frequency' } }
                }
            }
        });
    }

    function renderCompletionChart(histData, confidence) {
        histData.sort(function (a, b) { return a.days - b.days; });

        // Left-to-right: finish within X days with confidence%
        var total = histData.reduce(function (s, d) { return s + d.frequency; }, 0);
        var cumulative = 0;
        var percentile = null;
        for (var i = 0; i < histData.length; i++) {
            cumulative += histData[i].frequency;
            if (cumulative / total >= confidence / 100) {
                percentile = histData[i].days;
                break;
            }
        }

        completionDisplay.textContent = confidence + '% (' + percentile + ' days)';

        if (completionChart) { completionChart.destroy(); }
        completionChart = new Chart(
            document.getElementById('completionChart').getContext('2d'), {
            type: 'bar',
            data: {
                labels: histData.map(function (d) { return d.days; }),
                datasets: [{
                    label: 'Occurrences',
                    data: histData.map(function (d) { return d.frequency; }),
                    backgroundColor: 'rgba(153, 102, 255, 0.2)',
                    borderColor: 'rgba(153, 102, 255, 1)',
                    borderWidth: 1,
                    barPercentage: 1.0,
                    categoryPercentage: 1.0
                }]
            },
            options: {
                plugins: {
                    annotation: {
                        annotations: {
                            confidenceLine: {
                                type: 'line',
                                xMin: percentile,
                                xMax: percentile,
                                borderColor: 'red',
                                borderWidth: 2,
                                label: {
                                    content: String(percentile),
                                    enabled: true,
                                    position: 'start',
                                    backgroundColor: 'rgba(255, 99, 132, 0.8)',
                                    color: 'white',
                                    font: { size: 12, weight: 'bold' },
                                    padding: 6
                                }
                            }
                        }
                    }
                },
                scales: {
                    x: { type: 'linear', title: { display: true, text: 'Number of Days' } },
                    y: { beginAtZero: true, title: { display: true, text: 'Frequency' } }
                }
            }
        });
    }

    function renderBoth() {
        if (throughputData.length > 0) { renderThroughputChart(throughputData, confidenceValue); }
        if (completionData.length > 0) { renderCompletionChart(completionData, confidenceValue); }
    }

    // ── Run Simulation button ─────────────────────────────────────────────────
    runButton.addEventListener('click', function () {
        var days       = parseInt(daysInput.value, 10);
        var tasks      = parseInt(tasksInput.value, 10);
        var iterations = parseInt(iterationsInput.value, 10);
        var confidence = parseInt(confidenceInput.value, 10);

        if (isNaN(days)       || days <= 0)              { alert("Invalid days.");        return; }
        if (isNaN(tasks)      || tasks <= 0)             { alert("Invalid tasks.");       return; }
        if (isNaN(iterations) || iterations <= 0)        { alert("Invalid iterations.");  return; }
        if (isNaN(confidence) || confidence < 1 || confidence > 100) { alert("Invalid confidence."); return; }

        confidenceValue        = confidence;
        daysLabel.textContent  = days;
        tasksLabel.textContent = tasks;

        $scope.server.get({
            days:         days,
            tasks:        tasks,
            iterations:   iterations,
            queryTable:   tableInput.value,
            queryEncoded: queryInput.value,
            dateField:    datefieldInput.value
        }).then(function (response) {
            throughputData     = response.data.throughputHistogramData || [];
            completionData     = response.data.completionHistogramData || [];
            throughputBinWidth = response.data.throughputBinWidth || 1;
            completionBinWidth = response.data.completionBinWidth || 1;
            renderBoth();
        });
    });

    // ── Confidence slider updates charts instantly without re-simulation ───────
    confidenceInput.addEventListener('input', function () {
        var value = parseInt(confidenceInput.value, 10);
        if (value >= 1 && value <= 100) {
            confidenceValue = value;
            renderBoth();
        }
    });

    // ── Initial render with server data ───────────────────────────────────────
    renderBoth();
};

sp_widget.css:
.mc-header {
    background: #f4f4f4;
    border-bottom: 1px solid #ddd;
    padding: 12px 16px;
    margin-bottom: 20px;
}
.mc-header h1 {
    margin: 0 0 12px 0;
    font-size: 20px;
}
.mc-inputs {
    display: flex;
    flex-wrap: wrap;
    gap: 12px;
    align-items: flex-end;
}
.mc-inputs .mc-field {
    display: flex;
    flex-direction: column;
    gap: 4px;
}
.mc-inputs label {
    font-size: 12px;
    color: #555;
    margin: 0;
}
.mc-inputs input {
    padding: 4px 6px;
    border: 1px solid #ccc;
    border-radius: 3px;
}
.mc-inputs input[type=number] { width: 70px; }
.mc-inputs input[type=text]   { width: 130px; }
#queryInput                   { width: 200px; }
.mc-run-btn {
    padding: 6px 18px;
    background: #176BCC;
    color: white;
    border: none;
    border-radius: 3px;
    cursor: pointer;
    font-size: 14px;
    align-self: flex-end;
}
.mc-run-btn:hover { background: #1258a8; }
.mc-charts {
    display: flex;
    gap: 20px;
}
.mc-chart-panel {
    flex: 1;
    min-width: 0;
}
.mc-chart-panel h3 {
    font-size: 15px;
    margin-bottom: 4px;
}
.mc-confidence-label {
    font-size: 13px;
    color: #555;
    margin-bottom: 8px;
}

sp_widget.script:
(function () {
    var days         = input && input.days         ? parseInt(input.days, 10)         : 14;
    var tasks        = input && input.tasks        ? parseInt(input.tasks, 10)        : 50;
    var iterations   = input && input.iterations   ? parseInt(input.iterations, 10)   : 10000;
    var queryTable   = input && input.queryTable   ? input.queryTable                 : 'incident';
    var queryEncoded = input && input.queryEncoded ? input.queryEncoded               : 'active=false';
    var dateField    = input && input.dateField    ? input.dateField                  : 'closed_at';

    var taskDataUtil = new McTaskUtil();
    var monteCarloSim = new McSimUtil();

    var dailyThroughput = taskDataUtil.getDailyThroughput(queryTable, dateField, queryEncoded);

    if (dailyThroughput.length === 0) {
        data.error = "No historical data available.";
        return;
    }

    // Shared histogram builder (Sturges binning)
    function buildHistogram(results, valueKey) {
        var sorted = results.slice().sort(function (a, b) { return a - b; });
        var minVal   = sorted[0];
        var maxVal   = sorted[sorted.length - 1];
        var numBins  = Math.ceil(1 + Math.log(results.length) / Math.log(2));
        var binWidth = Math.max(1, Math.ceil((maxVal - minVal + 1) / numBins));

        var histogram = {};
        for (var k = 0; minVal + k * binWidth <= maxVal; k++) {
            histogram[minVal + k * binWidth] = 0;
        }
        for (var r = 0; r < results.length; r++) {
            var binKey = minVal + Math.floor((results[r] - minVal) / binWidth) * binWidth;
            histogram[binKey]++;
        }

        var histData = Object.keys(histogram).map(function (key) {
            var item = { frequency: histogram[key] };
            item[valueKey] = parseInt(key, 10);
            return item;
        });
        histData.sort(function (a, b) { return a[valueKey] - b[valueKey]; });
        return { data: histData, binWidth: binWidth };
    }

    // Simulation 1: How many tasks in X days?
    var throughputResults = monteCarloSim.simulateThroughput(days, iterations, dailyThroughput);
    var throughputHist    = buildHistogram(throughputResults, 'throughput');
    data.throughputHistogramData = throughputHist.data;
    data.throughputBinWidth      = throughputHist.binWidth;

    // Simulation 2: How many days to complete X tasks?
    var completionResults = monteCarloSim.simulateDaysToComplete(tasks, iterations, dailyThroughput);
    var completionHist    = buildHistogram(completionResults, 'days');
    data.completionHistogramData = completionHist.data;
    data.completionBinWidth      = completionHist.binWidth;
})();
